-- Inserir as 80 novas questões do concurso PM MT

-- BLOCO 1 - CLPAP (Peso 1.0) - Questões 1-20
INSERT INTO questao (id, pergunta, alternativa_a, alternativa_b, alternativa_c, alternativa_d, alternativa_e, resposta_correta, disciplina, peso) VALUES
('1', 'Deixe a seriedade para as horas em que ela é inevitável: mortes, separações, dores e afins. No dia a dia, pelo amor de Deus, seja idiota! Ria dos próprios defeitos. E de quem acha defeitos em você. (JABOR, A. Disponível em: https://www.pensador.com/conselhos_textos_arnaldo_jabor/. Acesso em: 25/10/2019.)Acerca de recursos linguísticos no texto, assinale a afirmativa correta.', 'O adjetivo inevitável, na primeira frase, pode ser substituído, sem prejuízo do sentido, por inexorável.', 'O pronome relativo em que, na primeira frase, pode ser substituído, sem prejuízo do sentido, por onde.', 'A expressão adverbial No dia a dia está acompanhada de vírgula para indicar que uma palavra foi suprimida.', 'O termo próprios está em desacordo com as regras de concordância da escrita padrão, pois concorda apenas em número com o substantivo a que se refere.', 'Os verbos deixar e rir estão empregados no presente do subjuntivo a indicar uma ação incerta no presente.', 'A', 'CLPAP', 1.0),

('2', 'A ONU estima que existam 250 milhões de expatriados no mundo, entre legalizados e ilegais. E, se dependesse apenas da vontade das pessoas, esse número poderia ser ainda maior. Uma pesquisa recém-divulgada pelo Instituto Gallup, dos EUA, indica que 750 milhões de pessoas sonham em morar em um país diferente. Um em cada seis adultos do planeta. (Superinteressante. https://super.abril.com.br/sociedade/imigracao. Acesso em 25/06/2019.) O Novo Acordo ortográfico tornou obrigatório o uso de hífen diante de certos prefixos, a exemplo de recém-divulgada. Assinale a alternativa em que o prefixo de todas as palavras exige a presença de hífen.', 'Sem-teto, bio-ritmo, semi-círculo.', 'Aquém-mar, manda-chuva, super-aquecimento.', 'Pré-vestibular, inter-estelar, ultra-resistente.', 'Ex-aluno, sem-terra, pós-doutorado.', 'Anti-higiênico, infra-estrutura, sub-emprego.', 'D', 'CLPAP', 1.0),

('3', 'Quanto a normas gramaticais da escrita padrão, relativas às concordâncias, analise as afirmativas. I- As moradoras do assentamento Santo Antônio construíram elas próprias o prédio para a capela. II- Mais de um deputado deixou de apoiar seu partido político em função de interesses particulares. III- O jovem garante que fazem meses desde sua última refeição substanciosa. IV- Certamente vai começar os jogos do campeonato brasileiro de futebol com os jogadores descansados. V- As férias são um período de descanso em que os trabalhadores refazem suas combidas energias. Estão corretas as afirmativas', 'III e IV, apenas.', 'I, III e IV, apenas.', 'II, III e V, apenas.', 'I, II, IV e V, apenas.', 'I, II e V, apenas.', 'E', 'CLPAP', 1.0),

('4', '[...] No Brasil, três em cada dez meninos ou meninas com idade entre 4 e 6 anos têm um celular para chamar de seu. A frequência do uso aumenta exponencialmente. Segundo pesquisa da Common Sense Media, organização americana sem fins lucrativos destinada a rastrear os hábitos tecnológicos da juventude, mais que dobrou o tempo da petizada diante dos vídeos, chegando à média diária (média!) de uma hora. Um detalhe: no YouTube, menores de 13 anos não poderiam ver vídeos (o correto é acessar a versão Kids), e, no entanto, os cliques não param. O Facebook também restringe o acesso a maiores de 13 anos, no entanto, segundo pesquisas recentes, 50% dos menores de 12 anos no Brasil estão lá. Há, enfim, uma avalanche de consumo precoce de conteúdo emitido pelas telas pequenas, à mão. [...] Em vez de lutarem contra a maré virtual, o fundamental é os pais assumirem a responsabilidade de educar as crianças para lidar com o mundo virtual. [...] A chave, enfim, é o bom senso. Soa inaceitável afastar crianças e adolescentes da conexão digital – mas achar que um smartphone pode fazer as vezes de pai, mãe e professor é errado. (LOPES, A. Revista Veja, ed. 2661. Adaptado.) Sobre o texto, marque V para as afirmativas verdadeiras e F para as falsas. ( ) Apesar de YouTube e Facebook serem destinados a pessoas acima de 13 anos, crianças abaixo dessa idade consomem o conteúdo dessas tecnologias em grande quantidade. ( ) O articulista critica com veemência o uso de mídias digitais por crianças e a conivência dos pais, mas não apresenta proposta de solução para o problema. ( ) Os argumentos da OMS para limitar o uso de mídias digitais a determinadas faixas etárias das crianças compreendem argumentos pertinentes, relacionados à saúde física, mental e cognitiva. ( ) As expressões Segundo pesquisa da Common Sense Media e segundo pesquisas recentes introduzem argumentos de autoridade. Assinale a sequência correta.', 'V, V, F, F', 'V, F, V, V', 'F, F, V, V', 'F, V, F, F', 'V, F, F, V', 'B', 'CLPAP', 1.0),

('5', 'A respeito de recursos linguísticos e semânticos empregados no texto, assinale a afirmativa INCORRETA.', 'No trecho chegando à média diária (média!) de uma hora, a repetição da palavra média entre parênteses sugere espanto do autor diante do tempo gasto diariamente pelos jovens com mídias digitais.', 'A primeira frase do texto pode ser reescrita, sem prejuízo do sentido e da correção gramatical, da seguinte maneira: Três em cada dez meninos ou meninas de 4 a 6 anos, no Brasil, possuem celular.', 'Na frase A frequência do uso aumenta exponencialmente., o advérbio de modo acrescenta ideia de linearidade, ou seja, aumenta de forma linear.', 'O vocábulo petizada é derivado de petiz, palavra antiga, hoje em desuso, que significa criança, assim petizada significa grupo de crianças, garotada, meninada.', 'No período O Facebook também restringe o acesso a maiores de 13 anos, no entanto, segundo pesquisas recentes, 50% dos menores de 12 anos no Brasil estão lá., a relação de coordenação entre as orações expressa o sentido de oposição.', 'C', 'CLPAP', 1.0),

('6', 'Pode ser em casa, na farmácia ou no consultório... Medir a pressão de vez em quando é uma das atitudes mais importantes para saber como está sua saúde e prevenir problemas relacionados à hipertensão, como infarto e acidente cerebral vascular. Dos participantes de uma enquete, 74% disseram saber o valor de sua última aferição – destes 31% apresentam os níveis acima de 12 por 8, o que pode demandar mudanças na alimentação, prática de exercícios e até prescrição de remédios. Chama a atenção ainda o fato de 26% não terem ideia de como está sua pressão. Que tal medi-la hoje mesmo? É simples, barato e salva vidas. (Revista Saúde, n° 427.) Sobre o texto, assinale a afirmativa INCORRETA.', 'Na frase interrogativa – Que tal medi-la hoje mesmo? – o pronome la retoma o sentido de pressão, exercendo a função de elemento coesivo referencial anafórico.', 'A primeira frase do texto – Pode ser em casa, na farmácia ou no consultório... – refere-se ao ato de medir a pressão, ideia que se apresenta na frase seguinte.', 'A última frase do texto – É simples, barato e salva vidas. – refere-se ao ato de medir a pressão.', 'Alimentação adequada, exercícios e medicamentos são cogitados para pessoas com pressão acima de 12 por 8.', 'Os 31% que apresentam os níveis de pressão acima de 12 por 8 remetem aos 100% dos participantes da enquete.', 'E', 'CLPAP', 1.0),

('7', '(Armandinho. http://tirasbeck.blogspot.com.br Acesso em 30/01/2021.) Na tira, há três palavras homófonas heterográficas: cestas, sestas e sextas. Sobre a significação das palavras (sinônimas, antônimas, homônimas, polissêmicas, conotativas e denotativas), assinale a afirmativa correta.', 'Na frase Os antagonistas de um partido político nem sempre se posicionam como adversários, depende de seus interesses políticos, há exemplo de antonímia.', 'Na frase A descrição da obra, feita pelo crítico, revelou toda discrição que ele usou para não ferir suscetibilidades, há exemplo de homonímia perfeita.', 'Na frase As luzes a serem encontradas no paraíso contrastam com as trevas do inferno, há exemplo de sinonímia.', 'Na frase Todos sabem que aquele político passou a nadar em ouro após assumir alto posto, há exemplo de conotação.', 'Na frase No final do filme, o facínora conseguiu sair da cela, colocou uma sela em um cavalo e fugiu em disparada., há exemplo de homonímia homográfica.', 'D', 'CLPAP', 1.0),

('8', 'Para Jamila Jorge Ferrari, delegada coordenadora das Delegacias de Defesa da Mulher de São Paulo, denunciar o companheiro agressor é a única forma de interromper a escalada de violência que pode culminar no feminicídio. Por que o feminicídio tem aumentado? Há vários fatores. O feminicídio passou a ser uma agravante em 2005, então a polícia levou um tempo para fazer o registro da forma correta. Há também o fato de as mulheres terem mais coragem de denunciar e de a imprensa estar mais interessada na pauta. É um crime que existe desde sempre. Por quê? Ninguém começa um relacionamento dando um tapa na cara. A agressão vem em escala contínua. Os primeiros sinais ocorrem quando o companheiro sugere que a mulher não use determinada roupa, pede para ver o celular e para ela evitar certas amizades. Isso evolui para um esbarrão, tapa, soco e, em último caso, o feminicídio. Trata-se de um crime não premeditado. Em geral, é um ataque de fúria com muita crueldade. [...] Como evitar esse crime? Além da importância de denunciar o agressor em casos imediatos, a longo prazo esse quadro só será transformado com a educação. A Espanha reduziu os casos de feminicídio porque as escolas públicas e particulares passaram a dar aulas sobre igualdade de gênero e respeito ao próximo. Não podemos esquecer: homens machistas foram criados por mulheres machistas. O machismo não está no DNA, ele é uma construção social. Enquanto as escolas não tiverem um programa para ensinar que todos temos os mesmos direitos e importância, não haverá evolução. (Revista Veja, Ed. 2674.) A respeito do texto, analise as afirmativas. I- A resposta à primeira pergunta leva ao entendimento de que o feminicídio não é fato recente, mas, como as mulheres agressadas não o denunciavam, as autoridades não o consideravam crime. II- A entrevistada, na segunda resposta, descreve como o feminicídio ocorre, de pequenos fatos agressivos ao crime propriamente. III- Na terceira resposta, é dada como solução a atuação da escola com programas especiais sobre direitos humanos e igualdade de gêneros. Está correto o que se afirma em', 'I, II e III.', 'II e III, apenas.', 'III, apenas.', 'I e II, apenas.', 'I e III, apenas.', 'A', 'CLPAP', 1.0),

('9', 'O verbo haver, quando indica existir, ocorrer, acontecer, é usado como impessoal, ao contrário do existir que é flexionado. No texto, há exemplos como Há vários fatores. e É um crime que existe desde sempre. Sobre a concordância desses verbos, marque C para o uso correto e I para o incorreto. ( ) Mesmo com a pandemia, havia muitas pessoas na entrega dos prêmios. ( ) O prefeito garantiu que existirá mudanças na metodologia de aplicação das vacunas. ( ) Houve várias questões em pauta na reunião dos condôminos na sexta-feira passada. ( ) Não existirão mais pássaros nos céus se o homem continuar a depredar o meio ambiente. ( ) Ele afirmou taxativamente que houveram problemas sérios a serem resolvidos. Assinale a sequência correta.', 'C, I, C, C, I', 'C, C, I, I, C', 'I, I, C, I, C', 'I, C, I, C, I', 'C, I, I, C, C', 'A', 'CLPAP', 1.0),

('10', 'Leia atentamente as frases a seguir. • Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. • A imperícia social vinculada ao déficit em letramento digital fomenta a perpetuação do problema. • As instituições educacionais ainda não são eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. • A formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação. Juntando essas frases, com as alterações adequadas, de modo a formar um parágrafo coeso, ficará:', 'Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. Mas a imperícia social vinculada ao déficit em letramento digital fomenta a perpetuação do problema. Também as instituições educacionais ainda não são eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. Assim, a formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação.', 'Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. A imperícia social vinculada ao déficit em letramento digital fomenta a perpetuação do problema, apesar de as instituições educacionais ainda não serem eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. Por isso, a formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação.', 'Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. De um lado, a imperícia social vinculada ao déficit em letramento digital fomenta a perpetuação do problema, de outro, as instituições educacionais ainda não são eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. Assim, a formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação.', 'Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. Embora a imperícia social vinculada ao déficit em letramento digital fomente a perpetuação do problema, as instituições educacionais ainda não são eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. Portanto, a formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação.', 'Hoje, existe manipulação das ações humanas em razão do uso das tecnologias, que findam por influenciar o comportamento dos indivíduos. Apesar de a imperícia social vinculada ao déficit em letramento digital fomentar a perpetuação do problema, de outro, mas as instituições educacionais ainda não são eficazes na educação tecnológica, por não contarem com estrutura profissional e material voltada ao tema. Logo, a formação de indivíduos vulneráveis possibilita a ação do mecanismo que pode transformar comportamentos, tornando-os passíveis de alienação.', 'C', 'CLPAP', 1.0),

('11', 'Sobre o Poder de Polícia exercido pela Administração Pública, assinale a afirmativa INCORRETA.', 'Limita o uso, gozo e disposição da propriedade e restringe o exercício da liberdade dos indivíduos em benefício do interesse público.', 'Restringe direitos individuais, interferindo na órbita do interesse privado, para salvaguardar o interesse público.', 'Admite até o emprego da força pública para o seu normal cumprimento, quando houver resistência por parte do administrado.', 'Impede ou paralisa atividades antissociais.', 'Atua para a punição de agentes públicos que se recusarem a executar as tarefas em conformidade com as determinações superiores, desde que manifestamente legais.', 'E', 'CLPAP', 1.0),

('12', 'Os ente da administração indireta nascem, instrumentalizados por meio de leis específicas, da modalidade de descentralização administrativa por', 'avocação.', 'território.', 'desconcentração.', 'delegação.', 'outorga.', 'E', 'CLPAP', 1.0),

('13', 'Para que a Administração Pública possa executar as tarefas que lhe competem e, entre elas, fazer prevalecer o interesse público ao privado, o ordenamento lhe confere poderes. São Poderes Administrativos:', 'De Polícia, Regimental, Originário, Punitivo.', 'Originário, Regulamentar, Disciplinar, De Controle.', 'De Controle, Regimental, Jurisdicional, Hierárquico.', 'Regulamentar, Disciplinar, Hierárquico, De Polícia.', 'Hierárquico, Punitivo, Jurisdicional, Originário.', 'D', 'CLPAP', 1.0),

('14', 'A respeito dos Atos Administrativos, marque V para as afirmativas verdadeiras e F para as falsas. ( ) A autoexecutoriedade tem como fundamento salvaguardar o interesse público e o ato pode ser executado imediatamente se tiver o crivo do Judiciary. ( ) A finalidade é um dos atributos do ato administrativo e descreve o que o administrador pretende realizar. ( ) O motivo é a situação de fato ou de direito que gera a vontade do agente quando pratica o ato administrativo. ( ) A imperatividade é um dos requisitos do ato administrativo e estabelece a possibilidade de a administração pública definir, unilateralmente, quais serão os atos de consentimento. ( ) O sujeito dos atos administrativos são os agentes da administração e seus delegatários, desde que exerçam função administrativa. Assinale a sequência correta.', 'F, F, V, F, V', 'V, V, F, V, F', 'F, V, F, F, V', 'V, F, V, V, F', 'F, F, F, V, V', 'A', 'CLPAP', 1.0),

('15', 'No que se refere ao controle administrativo, analise as afirmativas. I- O controle administrativo é exercido pelo Executivo e pelos órgãos administrativos do Legislativo e do Judiciário. II- O controle interno administrativo permite à Administração rever, anular ou revogar os seus próprios atos. III- O controle do mérito da conduta administrativa é privativo dos Tribunais de Contas, que deverão verificar a conveniência e oportunidade. IV- O controle prévio, concomitante ou posterior pode ser exercido sobre a conduta administrativa. V- O controle da legalidade da ação administrativa deve ser exercido pelo poder judiciário. Estão corretas as afirmativas', 'III, IV e V, apenas.', 'II, IV e V, apenas.', 'I e III, apenas.', 'I, II e IV, apenas.', 'II e V, apenas.', 'D', 'CLPAP', 1.0),

('16', 'Na administração pública, dentro das atividades básicas de almoxarifado, o recebimento definitivo de material adquirido com valor superior ao limite estabelecido para a modalidade Convite deverá ser confiado', 'ao chefe do almoxarifado, formalmente nomeado.', 'a uma comissão de, no mínimo, três membros.', 'diretamente à unidade solicitante, dentro do processo de distribuição.', 'a uma comissão composta necessariamente pelo chefe do almoxarifado e pelo controle interno.', 'ao responsável pela aquisição para assegurar que a descrição do material esteja correta.', 'B', 'CLPAP', 1.0),

('17', 'Na coluna da esquerda estão dispostos os conceitos e, na da direita, a definição para aplicação na Administração Pública. Numere a coluna da direita de acordo com com a da esquerda. 1- Efetividade da gestão pública ( ) Capacidade de atingir resultados com a melhor utilização dos recursos disponíveis. 2- Eficiência administrativa ( ) Capacidade de atingir os resultados pretendidos com o máximo de alcance da meta traçada. 3- Eficácia dos gastos públicos ( ) Capacidade de atingir resultados atendendo as reais prioridades. Assinale a sequência correta.', '3, 1, 2', '1, 2, 3', '3, 2, 1', '2, 1, 3', '2, 3, 1', 'E', 'CLPAP', 1.0),

('18', 'Sobre o modelo de Gestão de Competências, leia o texto. No modelo de Gestão por Competência a fase de ___________ tem como foco identificar qual a diferença entre competências já existentes e aquelas necessárias para que a organização cumpra com sucesso a sua estratégia de atuação. Assinale a alternativa que preenche corretamente a lacuna.', 'implantação do sistema de retribuição e incentivos', 'acompanhamento e avaliação', 'formulação da estratégia da organização', 'mapeamento de competências', 'captação ou desenvolvimento de competências', 'D', 'CLPAP', 1.0),

('19', 'Sobre a análise SWOT, considerando o ambiente interno e externo, analise as afirmativas. I- Oportunidades são atributos positivos tangíveis e intangíveis internos a uma organização. II- Por meio de uma autoanálise, a organização poderá entender quais são as suas fraquezas. III- O parque tecnológico atualizado e voltado para a melhoria do atendimento representa um ponto forte a ser explorado pela organização. IV- Os fatores que prejudicam a capacidade de a organização atingir suas metas, ainda que estejam em seu controle, são considerados ameaças. Estão corretas as afirmativas', 'II e III, apenas.', 'I, II e IV, apenas.', 'III e IV, apenas.', 'I, III e IV, apenas.', 'I e II, apenas.', 'A', 'CLPAP', 1.0),

('20', 'Competência, como definida na Lei nº 7.692/2002, é a fração do poder político autônomo do Estado, conferida pela Constituição ou pela lei como própria e irrenunciável dos órgãos administrativos, salvo os casos de delegação e avocação legalmente admitidos. Acerca da competência, assinale a afirmativa correta.', 'Uma vez delegada, a autoridade delegante não poderá revogá-la.', 'Poderá ser totalmente delegada a outros órgãos, quando for conveniente, em razão de circunstância de índole econômica.', 'A edição de atos normativos que regulem direitos e deveres dos administrados não pode ser objeto de delegação.', 'A avocação poderá ocorrer, a qualquer tempo, desde que entre os órgãos da Administração Pública Direta.', 'As decisões de recursos administrativos podem ser delegadas somente em casos de desvio de finalidade.', 'C', 'CLPAP', 1.0);

-- BLOCO 2 - CPJM (Peso 1.25) - Questões 21-40
INSERT INTO questao (id, pergunta, alternativa_a, alternativa_b, alternativa_c, alternativa_d, alternativa_e, resposta_correta, disciplina, peso) VALUES
('21', 'De acordo com as disposições do Código Penal Militar (Decreto-Lei nº 1.001/1969 e alterações) acerca dos crimes militares em tempo de paz, é correto afirmar que são considerados crimes militares', 'os previstos no respectivo Código, ainda que igualmente definidos na lei penal comum, qualquer que seja o agente.', 'os previstos na legislação penal, quando praticados por civil contra militar em qualquer lugar.', 'os previstos no respective Código e na legislação penal, quando praticados por militar, em qualquer lugar, contra civil.', 'os previstos no respective Código e na legislação penal, quando praticados por militar em formatura contra outro militar, exceto quando fora do lugar sujeito à administração militar.', 'os praticados por militar da reserva, ou reformado, ou por civil contra o patrimônio sob a administração militar.', 'E', 'CPJM', 1.25),

('22', 'Considerando o disposto no Código de Processo Penal Militar (Decreto-Lei nº 1.002/1969 e alterações) acerca do exercício da polícia judiciária militar, marque V para as afirmativas verdadeiras e F para as falsas. ( ) A polícia judiciária militar é exercida pelos comandantes de forças e unidades, conforme as respectivas jurisdições. ( ) Obedecidas as normas regulamentares de jurisdição, hierarquia e comando, as atribuições inerentes ao exercício da polícia judiciária militar poderão ser delegadas a oficiais da ativa, inclusive por tempo ilimitado. ( ) A delegação para instauração de inquérito policial militar deverá recair em oficial de posto superior ao do indiciado, seja este oficial da ativa, da reserva, remunerada ou não, ou reformado. ( ) Não sendo possível a designação de oficial de posto superior ao do indiciado, poderá ser feita a de oficial do mesmo posto, desde que mais antigo, mas tal critério de antiguidade não prevalece se o indiciado é oficial da reserva ou reformado. Assinale a sequência correta.', 'F, V, V, F', 'V, F, F, V', 'V, F, V, V', 'V, F, V, F', 'F, V, F, V', 'C', 'CPJM', 1.25),

('23', 'Sobre o crime de violência contra inferior previsto no Código Penal Militar (Decreto-Lei nº 1.001/1969 e alterações), assinale a afirmativa correta.', 'Se da violência resulta lesão corporal ou morte, é aplicada somente a pena do crime contra a pessoa.', 'É punido com pena base igual ao do crime de violência contra superior.', 'É capitulado como crime de excesso ou abuso de autoridade.', 'Se da violência resulta lesão corporal ou morte, é aplicada a pena do crime contra a pessoa, desde que o agente tenha agido com dolo.', 'A pena base é de reclusão, de um a dois anos.', 'C', 'CPJM', 1.25),

('24', 'Conforme estabelece o Código de Processo Penal Militar (Decreto-Lei nº 1.002/1969 e alterações), as providências anteriores ao inquérito policial militar deverão ser tomadas ou determinadas', 'exclusivamente pelo comandante da corporação militar.', 'pelo oficial responsável por comando, direção ou chefia, ou aquele que o substitua ou esteja de dia, de serviço ou de quarto, assim que tiver conhecimento de infração penal que lhe incumba reprimir ou evitar.', 'por qualquer autoridade militar, que tenha conhecimento da prática de infração penal, desde que expressamente designada para apuração do fato, que configure crime militar, e de sua autoria.', 'pelo oficial responsável por comando, direção ou chefia, a partir do momento em que receber delegação da autoridade superior para apuração do fato, que configure crime militar, e de sua autoria.', 'exclusivamente pela chefia do militar a ser indiciado, podendo tal atribuição ser avocado pela autoridade superior.', 'B', 'CPJM', 1.25),

('25', 'Em conformidade com o disposto no Código de Processo Penal Militar (Decreto-Lei nº 1.002/1969 e alterações), NÃO é considerada medida preliminar ao inquérito policial militar:', 'A oitiva de testemunhas.', 'A preservação do estado e da situação das coisas no local da ocorrência.', 'A apreensão dos instrumentos e de todos os objetos que tenham relação com o fato.', 'A colheita de provas que sirvam para o esclarecimento do fato e suas circunstâncias.', 'A prisão do infrator.', 'A', 'CPJM', 1.25),

('26', 'Analise a seguinte situação hipotética. Honestino, oficial militar em atividade no Estado de Mato Grosso, foi designado para a função de diretor de Escola Militar de Ensino Fundamental e Médio. Em virtude do licenciamento de professores efetivos, a Escola realizou processo seletivo para contratação temporária de professores. Após a homologação e publicação do resultado final, alguns candidatos classificados desistiram, razão pela qual Honestino convocou e determinó a contratação de candidatos que não atenderam a todos os requisitos para aprovação no certame. Após denúncia dirigida ao Ministério Público Estadual, foi instaurado inquérito civil para apurar a prática de ato de violação da licitude de concurso público. De acordo com os ditames da Lei nº 8.429/1992, a conduta de Honestino, em tese, configura ato de improbidade administrativa que', 'decorre da concessão indevida de benefício financeiro.', 'causa prejuízo ao erário.', 'importa enriquecimento ilícito.', 'atenta contra os princípios da Administração Pública.', 'retarda a aplicação de recursos públicos.', 'D', 'CPJM', 1.25),

('27', 'Nos termos da Lei nº 8.429/1992, que dispõe sobre as sanções aplicáveis aos agentes públicos que praticarem atos de improbidade administrativa, a posse e o exercício de agente público ficam condicionados à apresentação de declaração dos bens e valores que compõem o seu patrimônio privado, a fim de ser arquivada no serviço de pessoal competente. Segundo as disposições legais acerca do tema, o agente público que se recusar a prestar declaração dos bens, dentro do prazo determinado, ou prestar declaração falsa, será punido com a', 'pena de suspensão do cargo pelo prazo de 60 dias, sem prejuízo de outras sanções cabíveis.', 'pena de demissão, a bem do serviço público, sem prejuízo de outras sanções cabíveis.', 'suspensão dos direitos políticos de dois a quatro anos.', 'aplicação de multa civil de até dez vezes o valor da remuneração mensal.', 'aposentadoria compulsória com proventos proporcionais ao tempo de contribuição.', 'B', 'CPJM', 1.25),

('28', 'A Lei nº 9.455/1997 define como crime de tortura constranger alguém com emprego de violência ou grave ameaça, causando-lhe sofrimento físico ou mental, com o fim de obter informação da vítima ou de terceira pessoa. Segundo as disposições legais acerca do tema, aquele que se omite, em face da prática de tal conduta, quando tinha o dever de evitá-la ou apurá-la,', 'se for agente público, somente responderá na esfera cível por ato de improbidade administrativa.', 'responde pelo crime de omissão de socorro, nos termos da legislação penal.', 'incorre na mesma pena de quem praticou o ato.', 'se condenado, iniciando o cumprimento da pena em regime fechado.', 'incorre na pena de detenção de um a quatro anos.', 'E', 'CPJM', 1.25),

('29', 'Leia a notícia abaixo: «(…) Conforme os autos, no dia 21 de maio de 2008, por volta das 19 h, no Sítio Várzea, localizado no Município (…)». (Fonte: Tribunal de Justiça do Estado da Paraíba. Disponível em: http://www.lex.com.br/noticia_27823547_. Acesso em: 07 fev. 2021.) Considerando que a notícia narra um caso concreto envolvendo a condenação criminal de um policial militar e um agente penitenciário, analise as assertivas. I- A conduta dos acusado, nos termos da legislação penal especial, configura crime de tortura qualificada pelo resultado morte. II- Há previsão legal de agravamento da pena em caso de crime de tortura cometido por agente público. III- A pena do crime de tortura é aumentada se a vítima é adolescente. IV- A condenação acarretará a perda do cargo público e a interdição para seu exercício pelo prazo da pena aplicada. Estão corretas as assertivas', 'III e IV, apenas.', 'I, II e IV, apenas.', 'I, II e III, apenas.', 'I, III e IV, apenas.', 'II e III, apenas.', 'C', 'CPJM', 1.25),

('30', 'Tendo em vista as disposições gerais da Lei nº 13.869/2019, que define os crimes de abuso de autoridade, é INCORRETO afirmar:', 'Constitui crime de abuso de autoridade a conduta praticada pelo agente público com a finalidade específica de beneficiar a si mesmo ou a terceiro.', 'O agente público, servidor ou não, que, no exercício de suas funções ou a pretexto de exercê-las, abuse do poder que lhe tenha sido atribuído, comete crime de abuso de autoridade.', 'Constitui crime de abuso de autoridade a conduta praticada pelo agente público com a finalidade específica de prejudicar outrem.', 'A divergência na interpretação de lei ou na avaliação de fatos e provas pode configurar abuso de autoridade.', 'Constitui crime de abuso de autoridade a conduta praticada pelo agente público por mero capricho ou satisfação pessoal.', 'D', 'CPJM', 1.25),

('31', 'Segundo os dispositivos da Lei nº 13.869/2019, que define os crimes de abuso de autoridade, acerca dos efeitos da condenação e das penas restritivas de direitos, assinale a afirmativa correta.', 'As penas restritivas de direitos podem ser aplicadas autônoma ou cumulativamente.', 'Deve o Juiz, a requerimento do ofendido, fixar na sentença o valor máximo para reparação dos danos causados pelo crime, considerando o caráter punitivo da obrigação de indenizar.', 'A perda do cargo, do mandato ou da função pública decorre automaticamente da condenação por crime de abuso de autoridade.', 'Em caso de reincidência em crime de abuso de autoridade, é prevista pena de inabilitação para o exercício de cargo, mandato ou função pública, pelo período de 2 (dois) a 8 (oito) anos.', 'O sujeito ativo do crime de abuso de autoridade poderá ser condenado à pena restritiva de direitos cumulada com a privativa de liberdade.', 'A', 'CPJM', 1.25),

('32', 'De acordo com a Lei nº 13.869/2019, que dispõe sobre os crimes de abuso de autoridade, haverá crime quando o agente policial', 'cumprir mandado de busca e apreensão domiciliar depois das 5 h (cinco horas) e antes das 21 h (vinte e uma horas).', 'ingressar, à revelia da vontade do ocupante, em imóvel alheio ou suas dependências.', 'permanecer em imóvel alheio ou suas dependências, sem determinação judicial, para prestar socorro.', 'ingressar em imóvel alheio ou suas dependências, quando houver fundados indícios de situação de flagrante delito.', 'adentar imóvel alheio ou suas dependências, quando houver fundados indícios da necessidade do ingresso em razão de desastre.', 'B', 'CPJM', 1.25),

('33', 'Em consonância com o previsto no Manual de IPM e Prisão em flagrante (aprovado pela Portaria nº 217/GCG/PMMT/09) acerca do interrogatório do indiciado no Inquérito Policial Militar, assinale a afirmativa correta.', 'O indiciado será advertido, no início do interrogatório, quanto ao seu dever de dizer a verdade, sob pena de ser enquadrado no crime de falso testemunho.', 'O advogado do indiciado não poderá acompanhar o interrogatório, em virtude do caráter sigiloso do procedimento inquisitório.', 'As interrogações dirigidas ao indiciado serão realizadas pelo escrivão designado para auxiliar o encarregado do Inquérito Policial Militar.', 'A confissão do indiciado, para que tenha valor de prova, deve ser feita perante autoridade competente, ser livre, espontânea, expressa e verossímil.', 'Cabe ao indiciado produzir prova de sua inocência, sob pena de ser condenado por falta de prova em contrário.', 'D', 'CPJM', 1.25),

('34', 'De acordo com o Manual de IPM e Prisão em flagrante (aprovado pela Portaria nº 217/GCG/PMMT/09), analise as assertivas acerca de prisão provisória durante o curso do Inquérito Policial Militar (IPM). I- A prisão em flagrante delito do militar desertor ou insubmisso é a única hipótese de prisão provisória admitida no curso do IPM. II- A decretação da prisão preventiva do indiciado, atendendo representação da autoridade encarregada do IPM, será admitida apenas quando houver prova cabal do fato delituoso e de sua autoria. III- Primariedade, bons antecedentes e ocupação lícita são circunstâncias que não inviabilizam a custódia provisória, quando verificada a gravidade do delito e a necessidade de garantia da ordem pública. IV- A prisão preventiva não será decreta se o juiz verificar, pelas provas constantes dos autos do inquérito, ter o agente praticado o fato enquanto sujeito à coação física irresistível. Estão corretas as assertivas', 'I e IV, apenas.', 'I, II e III, apenas.', 'II, III e IV, apenas.', 'I, III e IV, apenas.', 'III e IV, apenas.', 'E', 'CPJM', 1.25),

('35', 'Considerando o contido no Manual de IPM e Prisão em flagrante (aprovado pela Portaria nº 217/GCG/PMMT/09) acerca da prisão temporária no curso do Inquérito Policial Militar (IPM), assinale a afirmativa INCORRETA.', 'A prisão temporária justificada pela conveniência da instrução criminal é expressamente admitida no Código de Processo Penal Militar.', 'A prisão temporária será decreta pelo juiz pelo prazo de 5 (cinco) dias, prorrogável por igual período, em caso de extrema e comprovada necessidade.', 'Na hipótese de representação da autoridade policial, o juiz, antes de decidir acerca da prisão temporária, ouvirá o Ministério Público.', 'O encarregado do IPM poderá representar pela prisão temporária do indiciado, observando-se as disposições da legislação processual penal comum.', 'Decorrido o prazo de 5 (cinco) dias de detenção, o preso não será posto em liberdade se já tiver sido decreta sua prisão preventiva.', 'A', 'CPJM', 1.25),

('36', 'Em conformidade com o Manual de Deserção da PMMT, assinale a afirmativa correta sobre o crime de deserção.', 'O desertor, ao se apresentar espontaneamente, somente está sujeito à prisão mediante ordem escrita da autoridade judiciária.', 'Fica caracterizado o concurso de pessoas, quando houver vários desertores em um único evento.', 'A pena será reduzida à metade, caso o autor se apresente voluntariamente dentro de oito dias após a consumação da deserção.', 'A consumação do crime de deserção ocorre quando encerrado o prazo de graça, inclusive no caso de deserção instantânea.', 'O crime de deserção é de ação pública condicionada, pois o oferecimento da denúncia depende de prévia representação do superior do desertor.', 'C', 'CPJM', 1.25),

('37', 'O prazo de prescrição da ação penal aplicável ao crime de deserção, tal como abordado no Manual de Deserção da PMMT, é de', 'dois anos, a contar da captura ou apresentação espontânea do desertor.', 'quatro anos, a contar da captura ou apresentação espontânea do desertor.', 'oito anos, a contar da captura ou apresentação espontânea do desertor.', 'quatro anos, a contar da lavratura do Termo de Deserção.', 'dois anos, a contar da lavratura do Termo de Deserção.', 'B', 'CPJM', 1.25),

('38', 'Conforme previsto no Manual de Sindicância da Polícia Militar de Mato Grosso, o encarregado da Sindicância, tão logo receba a portaria ou determinação para instauração a Sindicância, deverá adotar uma série de providências. Apresentam-se, a seguir, 4 (quatro) dessas ações, que devem ser numeradas na ordem cronológica correta. ( ) Remeter os autos da Sindicância à autoridade delegante ou competente para solucioná-la, por ofício ou parte. ( ) Ouvir o ofendido, sindicado, testemunhas e outras pessoas que possam esclarecer os fatos. ( ) Analisar os fatos apurados e fazer seu relatório conclusivo. ( ) Identificando indícios do cometimento de transgressão, citar o acusado e oportunizar o direito ao contraditório e ampla defesa. Assinale a sequência correta.', '4, 1, 3, 2', '3, 2, 4, 1', '4, 3, 2, 1', '3, 1, 4, 2', '4, 2, 3, 1', 'A', 'CPJM', 1.25),

('39', 'Observando-se o procedimento previsto no Manual de Sindicância da Polícia Militar de Mato Grosso, quando da Sindicância resultar indício da existência de infração penal militar, a autoridade delegante ou competente para decidir encaminhará a solução para publicação em boletim, determinando a', 'abertura de processo administrativo disciplinar.', 'conversão da penalidade em punição disciplinar.', 'consulta ao Ministério Público acerca da regularidade do procedimento.', 'consulta à Corregedora acerca do cabimento de inquérito policial militar.', 'instauração de inquérito policial militar.', 'E', 'CPJM', 1.25),

('40', 'Analise a seguinte situação hipotética. O Comandante Geral da PMMT foi notificado de sentença transitada em julgado proferida pela justiça comum que condenou praça militar sem estabilidade à pena privativa de liberdade superior a 2 (dois) anos, em virtude da prática de lesão corporal, prevalecendo-se o agente das relações domésticas. Considerando os normativos da PMMT, a providência a ser adotada é', 'a delegação de competência ao superior do praça militar para fins de aplicação de medida cautelar restritiva de liberdade.', 'a instauração, pelo Comandante Geral, de Sindicância de caráter demissório, observado o direito do praça militar ao contraditório e à ampla defesa.', 'a aplicação imediata, pelo Comandante Geral, da pena de exclusão ex officio do praça militar condenado na justiça comum.', 'a instauração, pelo Comandante Geral, de inquérito policial militar para apurar a materialidade e a autoria do crime imputo ao praça.', 'a instauração, pelo superior do praça militar, de processo administrativo disciplinar, observado o direito ao contraditório e à ampla defesa.', 'B', 'CPJM', 1.25);

-- BLOCO 3 - CLIPM (Peso 1.75) - Questões 41-60
INSERT INTO questao (id, pergunta, alternativa_a, alternativa_b, alternativa_c, alternativa_d, alternativa_e, resposta_correta, disciplina, peso) VALUES
('41', 'O art. 2º da Constituição Federal de 1988 prescreve: «São Poderes da União, independentes e harmônicos entre si, o Legislativo, o Executivo e o Judiciary». Sobre o referido princípio constitucional da separação dos poderes, analise as assertivas. I- O sentido da separação dos poderes consiste, em rigor, na divisão entre as funções típicas e atípicas do poder estatal, visto que o poder do Estado como tal é divisível. II- No sistema de divisão dos poderes, inexiste qualquer hierarquia entre os respectivos órgãos e funções do poder estatal, todos operando na esfera de suas competências constitucionalmente estabelecidas. III- A separação dos poderes é caracterizada pela atuação conjunta dos três Poderes direcionada à consecução dos objetivos constitucionais, sendo tal atuação juridicamente limitada por esferas de competências próprias e mecanismos de controle recíprocos. IV- O princípio da separação dos poderes tem como objetivo o controle do poder pelo poder, o que se concretiza por um conjunto de técnicas, a citar o direito de veto do chefe do Poder Executivo, a aprovação pelo Legislativo do orçamento dos demais órgãos estatais e o controle judicial dos atos dos demais poderes. Estão corretas as assertivas', 'I, II e IV, apenas.', 'I, II e III, apenas.', 'III e IV, apenas.', 'II, III e IV, apenas.', 'I e III, apenas.', 'D', 'CLIPM', 1.75),

('42', 'Em relação aos direitos e garantias fundamentais consagrados na Constituição Federal de 1988, é correto afirmar:', 'As normas definidoras dos direitos e garantias fundamentais sempre dependem de regulamentação legal para sua aplicação.', 'O artigo 5º estabelece um rol exaustivo de direitos e garantias de cunho individual e coletivo constitucionalmente protegidos.', 'Os direitos e garantias expressos na Constituição não excluem outros decorrentes do regime e dos princípios por ela adotados.', 'Os tratados e convenções internacionais de direitos humanos aprovados, em sessão única, por três quintos dos votos dos membros do Congresso Nacional, são equivalentes às emendas constitucionais.', 'São designados como fundamentais no texto constitucional apenas os direitos e garantias individuais e coletivos positivados no artigo 5º.', 'C', 'CLIPM', 1.75),

('43', 'No tocante ao direito de greve conferido aos trabalhadores e aos servidores públicos pela Constituição Federal de 1988, assinale a assertiva INCORRETA.', 'É assegurado o direito de grego ao servidor público, a ser exercido com observância dos limites legais.', 'Compete aos trabalhadores decidir sobre a oportunidade de exercer o direito de grego e sobre os interesses que devam por meio dele defender.', 'A legislação reguladora da grego define os serviços e atividades essenciais e dispõe sobre o atendimento das necessidades inadiáveis da comunidade.', 'Os abusos cometidos por grego sujeitos os responsáveis às penalidades legais.', 'O direito de grego é uma garantia constitucional a ser exercida de forma individual ou coletiva pelo titular do direito.', 'E', 'CLIPM', 1.75),

('44', 'A respeito dos órgãos responsáveis pela segurança pública previstos na Constituição Federal de 1988, marque V para as afirmativas verdadeiras e F para as falsas. ( ) As polícias federal e rodoviária federal exercem, com exclusividade, as funções de polícia judiciária da União. ( ) A polícia rodoviária dos Estados e os agentes de trânsito dos Municípios, desde que estruturados em carreiras, na forma da lei, integram os órgãos de segurança pública. ( ) As polícias militares e os corpos de bombeiros militares, forças auxiliares e reserva do Executivo, subordinam-se aos Governadores dos Estados e do Distrito Federal. ( ) Às polícias penais, vinculadas ao órgão administrador do sistema penal da unidade federativa a que pertencem, cabe a segurança dos establecimientos penais. Assinale a sequência correta.', 'F, F, V, V', 'V, V, F, V', 'F, V, V, F', 'V, F, F, V', 'F, F, V, F', 'A', 'CLIPM', 1.75),

('45', 'Em conformidade com as normas pertinentes aos militares na Constituição do Estado de Mato Grosso, analise as assertivas. I- O Governador do Estado pode delegar o exercício do comando supremo da Polícia Militar e do Corpo de Bombeiros Militar ao Secretário de Estado de Segurança Pública. II- Os trabalhos de Perícia Oficial e Identificação Técnica serão prestados, e suas informações fornecidas, sempre que requisitados por Presidente de Inquérito Policial Militar. III- O inúmero de segurança e o habeas data contra atos do Comandante-Geral da Polícia Militar são julgados pelo Conselho de Justiça Militar Estadual. IV- Os Conselhos de Justiça Militar comporão a Vara Especializada da Justiça Militar, dirigida por juiz de direito de entrância especial integrante da magistratura de carreira. Estão corretas as assertivas', 'II, III e IV, apenas.', 'I, II e III, apenas.', 'II e IV, apenas.', 'I, II e IV, apenas.', 'I e III, apenas.', 'C', 'CLIPM', 1.75),

('46', 'Considerando o disposto na redação vigente do Decreto-Lei nº 667/1969 acerca da estrutura e organização da Polícia Militar, NÃO é correto afirmar:', 'A Polícia Militar será estruturada em órgão de Direção, de Execução e de Apoio, de acordo com as finalidades essenciais do serviço policial e as necessidades de cada Estado.', 'O período cumprido pelo policial militar em cargo ou função de natureza civil temporária poderá ser computado como tempo de serviço para promoção, por antiguidade ou merecimento, e transferência para a inatividade.', 'São considerados no exercício de função policial militar os policiais militares em função de instrutor ou de aluno de estabelecimento de ensino das Forças Armadas ou de outra Corporação Policial Militar, no país ou no exterior.', 'Exercem funções de natureza policial militar ou de interesse policial militar os policiais militares em atividade na Casa Militar do Governador, Gabinete do Vice-Governador e Órgãos da Justiça Militar Estadual.', 'São considerados no exercício de função policial militar os policiais militares colocados à disposição de outra corporação Policial Militar.', 'B', 'CLIPM', 1.75),

('47', 'De acordo com o preceito constitucional que disciplina competência legislativa, a criação de normas gerais sobre inatividades e pensões das polícias militares e dos corpos de bombeiros militares compete', 'privativamente à União.', 'concorrentemente à União, Estados e Distrito Federal.', 'privativamente aos Estados e Distrito Federal.', 'concorrentemente aos Estados e Distrito Federal.', 'suplementivamente à União.', 'A', 'CLIPM', 1.75),

('48', 'O artigo 43 do Estatuto dos Militares do Estado de Mato Grosso (Lei Complementar Estadual nº 555/2014), ao tratar da hierarquia e da disciplina, prescreve: «A precedência entre os militares da ativa, do mesmo grau _________, é assegurada pela no _________ ou _________, salvo nos casos de precedência funcional previstos em lei». Assinale a alternativa que preenche correta e respectivamente as lacunas.', 'funcional, classificação, posto, graduação.', 'hierárquico, classificação, posto, promoção.', 'disciplinar, classificação, cargo, graduação.', 'funcional, antigüidade, cargo, promoção.', 'hierárquico, antigüidade, posto, graduação.', 'E', 'CLIPM', 1.75),

('49', 'Nos termos do Estatuto dos Militares do Estado de Mato Grosso (Lei Complementar Estadual nº 555/2014), o desligamento ex officio do militar estadual da instituição, com caráter de penalidade aplicada após o devido processo legal, corresponde à', 'perda de posto ou patente.', 'exoneração do cargo.', 'demissão.', 'transferência para a reserva remunerada.', 'reforma.', 'C', 'CLIPM', 1.75),

('50', 'Quanto às medidas previstas no Estatuto dos Militares do Estado de Mato Grosso (Lei Complementar Estadual nº 555/2014) que podem afetar a situação funcional dos militares, numere a coluna da direita de acordo com a da esquerda. 1- Convocação ( ) É o ato pelo qual o militar agregado retorna à atividade profissional tanlogo cese o motivo que determinou a sua agregação. 2- Reintegração ( ) É o retorno do militar estadual com estabilidade ao cargo anteriormente ocupado e decorreu de inabilitação em curso ou estágio probatório relativo a outro cargo. 3- Reversão ( ) É a investasi do militar no cargo anteriormente ocupado, quando invalidada a sua demissão por decisão administrativa ou judicial. 4- Recondução ( ) É o retorno do militar da reserva remunerada ao serviço ativo por ato do Governador do Estado. Marque a sequência correta.', '3, 4, 1, 2', '1, 3, 2, 4', '4, 3, 2, 1', '3, 4, 2, 1', '4, 2, 1, 3', 'D', 'CLIPM', 1.75),

('51', 'Em conformidade com a Lei Estadual nº 10.076/2014, que dispõe sobre os critérios e condições que asseguram aos Oficiais e às Praças da ativa da Polícia Militar e do Corpo de Bombeiros Militar do Estado de Mato Grosso acesso à hierarquia militar, mediante promoção, de forma seletiva, gradual e sucessiva, leia as assertivas relativas aos critérios de promoção. I- Promoção _________: realizada somente para o posto de coronel, baseia-se no conjunto de habilidades, competências, atributos que distinguem e realçam o valor do Oficial entre seus pares, avaliados no decurso da vida profissional e no desempenho de cargos e comissões exercidos, especialmente no posto em que se encontra. II- Promoção _________: resulta de ato ou atos não comuns de coragem e audácia, que, ultrapassando os limites normais do cumprimento do dever, representam feitos altamente meritórios, seja pelos resultados alcançados ou pelo exemplo positivo deles emanados. III- Promoção _________: resulta do reconhecimento do Estado de Mato Grosso ao militar estadual julgado incapaz definitivamente para o serviço policial ou bombeiro militar por ferimento ou acidente de serviço ocorrido no cumprimento do dever ou em sua consequência. IV- Promoção _________: resulta do reconhecimento do Estado de Mato Grosso ao militar estadual falecido no cumprimento do dever ou em sua consequência, ou não promovido por motivo de óbito. Assinale a alternativa que preenche correta e respectivamente as lacunas.', 'por ato de bravura; por merecimento; por requerimento; em ressarcimento de preterição.', 'por merecimento; por ato de bravura; por invalidez permanente; post mortem.', 'por merecimento; por ato de bravura; por requerimento; post mortem.', 'por mérito intelectual; por merecimento; por invalidez permanente; post mortem.', 'por mérito intelectual; por merecimento; em ressarcimento de preterição; por ato de bravura.', 'B', 'CLIPM', 1.75),

('52', 'A Lei Estadual nº 10.076/2014 estabelece as condições básicas para que os militares da ativa do Estado de Mato Grosso possam concorrer à promoção por ordem hierárquica de colocación no quadro de Praça ou Oficial. Entre as referidas condições, inclui-se a seguinte: «(...) o conjunto de qualidades e atributos, caracterizados pela honra, dignidade, honestidade e seriedade que o militar estadual deve possuir no desempenho de suas funções e no convívio social, de modo a lhe conferir respeitabilidade perante a sociedade, seus superiores, pares e subordinados». Trata-se de definição legal da condição descrita como conceito', 'intelectual.', 'disciplinar.', 'profissional.', 'moral.', 'funcional.', 'D', 'CLIPM', 1.75),

('53', 'De acordo com o disposto na Lei Estadual nº 10.076/2014 acerca do processamento das promoções, contra o ato emanado da Comissão de Promoção de Praças, o militar estadual que se julgar prejudicado em seu direito poderá, no prazo de 05 (cinco) dias, contados da data de publicação do ato, impetrar recurso em', 'primeiro grau ao presidente da Comissão e em segundo grau ao Comandante-Geral da Instituição.', 'primeiro grau ao presidente da Comissão e em segundo grau ao Governador do Estado.', 'primeiro grau ao Comandante-Geral da Instituição e em segundo grau ao Governador do Estado.', 'instância única, ao presidente da Comissão.', 'instância única, ao Comandante-Geral da Instituição.', 'A', 'CLIPM', 1.75),

('54', 'Em consonância com as normas do Decreto nº 591/1980, que dispõe sobre o Regulamento de Movimentação para Oficiais e Praças, a modalidade de movimentação decorrente de promoção, reversão, exoneração, término de licença, conclusão ou interrupção de curso, é denominada', 'Remoção.', 'Nomeação.', 'Transferência.', 'Designação.', 'Classificação.', 'E', 'CLIPM', 1.75),

('55', 'Com base na redação vigente do Decreto-Lei nº 667/1969, é vedado aos Policiais Militares em atividade:', 'Participar como instrutor ou aluno de cursos ministrados em establecimientos oficiais federais.', 'Comparecer fardado, em serviço, em manifestações de caráter político-partidário.', 'Fazer parte de sociedades comerciais ou empresas industriais de qualquer natureza ou nelas exercer função ou emprego remunerados.', 'Ficar à disposição do Governo Federal, para o exercício de cargo ou função em órgãos federais.', 'Integrar missões peculiares das Forças Armadas, no Brasil ou no exterior, mediante convocação.', 'C', 'CLIPM', 1.75),

('56', 'Segundo o disposto na Lei Complementar Estadual nº 529/2014, que fixa o efetivo da Polícia Militar do Estado de Mato Grosso, marque V para as afirmativas verdadeiras e F para as falsas. ( ) É exigida graduação de ensino superior de Bacharelado em Direito, legalmente reconhecida, conforme disposição em edital, no concurso público de provas ou de provas e títulos para o Curso de Formação de Oficiais (CFO) ou equivalente. ( ) A graduação de nível superior, legalmente reconhecida, de grau bacharelado ou licenciatura, exceto tecnólogo, é requisito exigido no concurso público para o Curso de Formação de Soldados. ( ) A ascensão nas carreiras de policiais militares, após conclusão com aproveitamento nos cursos de formação, habilitação e adaptação, obedecerá à reserva de vagas de militares estaduais do sexo feminino para as devidas promoções nos respectivos quadros. ( ) Todo o efetivo dos quadros de Oficiais e de praças poderá ser empregado no policiamento ostensivo em atendimento às necessidades do serviço policial militar. Assinale a sequência correta.', 'V, V, F, V', 'V, F, F, V', 'F, V, V, F', 'V, F, V, V', 'F, F, V, F', 'B', 'CLIPM', 1.75),

('57', 'Considerando o disposto na Lei Complementar Estadual nº 386/2010 acerca da estrutura e organização básica da Polícia Militar do Estado de Mato Grosso, assinale a alternativa que NÃO apresenta órgão de execução da instituição.', 'Academia de Polícia Militar', 'Batalhão de Polícia Militar', 'Companhia Independente de Polícia Militar', 'Pelotão de Polícia Militar', 'Núcleo de Polícia Militar', 'A', 'CLIPM', 1.75),

('58', 'Segundo a Lei Complementar Estadual nº 386/2010, que dispõe sobre a estrutura e organização básica da Polícia Militar do Estado de Mato Grosso, a contratação de pessoal civil pelo Comando Geral da Polícia Militar', 'é admitida, exclusivamente para prestação de serviços gerais.', 'é vedada, pois todos os serviços de interesse da Corporação devem ser prestados exclusivamente por militares.', 'é admitida para prestação de serviços de qualquer natureza, desde que seja justificada a necessidade e a carência de pessoal militar.', 'é admitida, desde que não seja para o exercício de função militar, com vistas à prestação de serviços de natureza técnica, especializada ou para serviços gerais.', 'é admitida para prestação de serviços de qualquer natureza, desde que não seja para o exercício de função militar.', 'D', 'CLIPM', 1.75),

('59', 'Nos termos da Lei Complementar Estadual nº 386/2010, a organização das atividades da Polícia Militar do Estado de Mato Grosso em nível de execução, de acordo com as necessidades decorrentes das missões e características regionais, observará os seguintes parâmetros de divisão territorial: I- _________: espaço geográfico de responsabilidade de um Comando Regional de Policiamento. II- _________: espaço geográfico de responsabilidade de um Batalhão ou Companhia Independente. III- _________: espaço geográfico de responsabilidade de uma Companhia. IV- _________: espaço geográfico de responsabilidade de um Pelotão. V- _________: espaço geográfico de responsabilidade de um Núcleo Policial Militar. Assinale a alternativa que preenche correta e respectivamente as lacunas.', 'Área; Região; Setor; Subsector; Circunscrição.', 'Circunscrição; Região; Área; Setor; Subsector.', 'Região; Setor; Subsector; Área; Subárea.', 'Área; Região; Circunscrição; Setor; Subsector.', 'Região; Área; Subárea; Setor; Subsector.', 'E', 'CLIPM', 1.75),

('60', 'Em conformidade com o Decreto n° 1.400/2012, que aprova o Regulamento de Uniformes da Polícia Militar do Estado de Mato Grosso, é correto afirmar:', 'É proibido o ingresso, a saída ou o desempenho de atividades administrativas, por integrantes da Polícia Militar em establecimientos policiais militares, em trajes civis.', 'Todos os uniformes previstos no Regulamento são de posse obrigatória do policial militar.', 'O uso correto dos uniformes é relevante para o fortalecimento da disciplina, o desenvolvimento do espírito de corpo e o bom conceito da Corporação no seio da opinião pública.', 'Aos policiais militares, é vedado apresentar-se, em órgãos públicos ou privados, em trajes civis, pelo fato de não ostentarem distintivo policial para sua identificação.', 'A critério do Comandante-Geral, poderá ser autorizado a particulares, instituições públicas ou privadas, o uso de trajes que se assemelham aos uniformes dos policiais militares.', 'C', 'CLIPM', 1.75);

-- BLOCO 4 - CP (Peso 2.0) - Questões 61-80
INSERT INTO questao (id, pergunta, alternativa_a, alternativa_b, alternativa_c, alternativa_d, alternativa_e, resposta_correta, disciplina, peso) VALUES
('61', 'Quanto ao uso progressivo da força policial, o processo 108 do Módulo I do Manual de Procedimento Operacional Padrão estabelece que, no cumprimento das funções, os responsáveis pela aplicação da lei devem, na medida do possível, aplicar meios não violentos antes de recorrer ao uso da força e armas de fogo. Contudo, sempre que o uso legítimo da força e de armas de fogo for inevitável, determinadas condutas deverão ser observadas pelo efetivo policial. Sobre tais condutas, analise as assertivas. I- Exercer moderação no uso de tais recursos e agir na proporção da gravidade da infração e do objetivo legítimo a ser alcançado. II- Minimizar danos e ferimentos, respeitar e preservar a vida humana. III- Garantir a prioridade na assistência e cuidados médicos das vítimas feridas ou afetadas em relação aos infratores da lei. IV- Assegurar que os familiares ou amigos íntimos da pessoa ferida ou afetada sejam notificados o mais rápido possível. Estão corretas as assertivas', 'I, II, III e IV.', 'I, II e IV, apenas.', 'II e IV, apenas.', 'I e III, apenas.', 'I e II apenas.', 'B', 'CP', 2.0),

('62', 'No Módulo II do Manual de Procedimento Operacional Padrão, ao tratar da abordagem a infratores da lei, o Procedimento 203.2 traz referência ao tiro duplo disparado por policial durante uma ocorrência. Sobre o tema, assinale a assertiva INCORRETA.', 'Sob o aspecto do poder de parada, o tiro duplo é capaz de potencializar substancialmente a capacidade de defesa do calibre utilizado.', 'Caracteriza-se como dois disparos defensivos em curto espaço de tempo e a uma distância aproximada entre ambos realizados pelo policial em situação de legítima defesa própria ou de terceiros.', 'A situação de legítima defesa é caracterizada pela agressão injusta, ilegal e iminente contra a vida.', 'Segundo entendimento jurisprudencial, os dois disparos não configuram uso excessivo da força policial, mesmo que existentes outros meios de controle e defesa para repelir a agressão.', 'O agrupamento de disparos é uma técnica defensiva eficaz, agindo em benefício da atividade policial.', 'D', 'CP', 2.0),

('63', 'Quanto ao acompanhamento e cerco a veículo previsto no Procedimento 304.1 do Módulo III do Manual de Procedimento Operacional Padrão, marque V para as afirmativas verdadeiras e F para as falsas. ( ) Se o veículo suspeito parar durante o acompanhamento, somente deverá ser abordado se houver superioridade numérica por parte dos policiais. ( ) Ao executar a abordagem, havendo resistência, abrigar-se e empregar os meios necessários, por meio do uso progressivo da força para neutralizar a ação de reação. ( ) No caso da parada do veículo e fuga dos suspeitos a pé, informar o Centro de Operações para que adote providências quanto ao veículo abandonado e seguir no encalço dos suspeitos. ( ) Quando houver mudança de área, circunscrição ou Estado, parar o acompanhamento ou encalço e informar seu responsável imediatamente. Assinale a sequência correta.', 'V, F, V, F', 'V, F, F, V', 'F, V, V, F', 'F, V, F, V', 'V, V, F, F', 'E', 'CP', 2.0),

('64', 'Quanto às características do policiamento ostensivo descritas no respectivo Manual Básico, assinale a afirmativa correta.', 'As operações policiais militares, destinadas a suprir exigências não atendidas pelo policiamento existente em determinados locais, são executadas esporadicamente, em caráter supletivo, por meio de saturação.', 'Ação de presença real é a capacidade do policiamento ostensivo, em um espaço de tempo mínimo (tempo de resposta), acorrer a local onde uma ocorrência policial militar é iminente ou já tenha se verificado.', 'Ação de presença potencial consiste na presença física do policial militar, agindo por dissuasão nos locais onde a probabilidade de ocorrência seja grande.', 'O policiamento ostensivo deve ser organizado de maneira rígida, pois não lhe cabe reconhecer situações anormais que afetam a ordem pública.', 'O policiamento ostensivo é exercido para preservar o interesse geral de segurança pública nas comunidades, bem como para garantir a segurança pessoal de indivíduos ameaçados em sua integridade física.', 'A', 'CP', 2.0),

('65', 'Em relação aos princípios do policiamento ostensivo previstos no respectivos Manual Básico, complete as assertivas a seguir. I- _________: as atividades policiais militares são desenvolvidas para a preservação da ordem pública em seu sentido amplo. II- _________: o aproveitamento dos recursos públicos destinados à Polícia Militar deve ser realizado de forma a otimizá-los. III- _________: a cobertura de locais de risco não ocupados e o reforço do pessoal empenhado devem ser efetivados ordenadamente. IV- _________: providências táticas e técnicas devem ser adotadas para minimizar a surpresa, fazendo face ao fenômeno da evolução da criminalidade. Assinale a alternativa que preenche correta e respectivamente as lacunas.', 'Efetividade; Profundidade; Universalidade; Antecipação.', 'Profundidade; Efetividade; Antecipação; Universalidade.', 'Universalidade; Efetividade; Profundidade; Antecipação.', 'Universalidade; Profundidade; Efetividade; Antecipação.', 'Profundidade; Universalidade; Antecipação; Efetividade.', 'C', 'CP', 2.0),

('66', 'O Estatuto da Criança e do Adolescente (Lei nº 8.069/1990 e alterações) prevê a aplicação pela autoridade judiciária competente de medidas socioeducativas para o adolescente que cometer ato infracional. Sobre tais medidas, é correto afirmar:', 'A prestação de serviços comunitários consiste na realização de tarefas gratuitas de interesse geral, por período não excedente a doze meses, junto a entidades assistenciais, hospitais, escolas e outros establecimientos congêneres.', 'Em se tratando de ato infracional com reflexos patrimoniais, a autoridade determinará que os pais ou responsáveis promovam o ressarcimento do dano, ou, por outra forma, compensem o prejuízo da vítima.', 'A liberdade assistida será fixada pelo prazo mínimo de seis meses, podendo a qualquer tempo ser prorrogada, revogada ou substituída por outra medida, ouvido o orientador, o Ministério Público e o defensor.', 'O regime de semiliberdade pode ser determinado desde o início, ou como forma de transição para o meio aberto, possibilitada a realização de atividades externas, desde que precedidas de expressa autorização judicial.', 'A autoridade judiciária poderá determinar temporariamente a incomunicabilidade do adolescente sujeito à medida de internação.', 'C', 'CP', 2.0),

('67', 'Em conformidade com as disposições gerais do Estatuto da Criança e do Adolescente (Lei nº 8.069/1990 e alterações) acerca do acesso à justiça, analise as assertivas. I- Os menores de dezesseis anos serão representados por seus pais, tutores ou curadores, na forma da legislação civil ou processual. II- A autoridade judiciária dará curador especial à criança ou adolescente, sempre que os interesses destes colidirem com os de seus pais ou responsáveis. III- É vedada a divulgação de atos judiciais, policiais e administrativos que digam respeito a crianças e adolescentes a que se atribua autoria de ato infracional. IV- Qualquer notícia a respeito da prática de ato infracional não poderá identificar a criança ou adolescente, admitindo-se apenas a referência às iniciais do nome e sobrenome. Estão corretas as assertivas', 'I e IV, apenas.', 'I, II e IV, apenas.', 'II, III e IV, apenas.', 'II e III, apenas.', 'I, II e III, apenas.', 'E', 'CP', 2.0),

('68', 'Conforme previsto no Módulo II do Manual de Procedimento Operacional Padrão, ao tratar da abordagem a infratores da lei, assinale a assertiva correta acerca do procedimento de conferência visual após disparos.', 'O Policial deverá fazer a varredura do local e manter a arma em posição de pronto alto.', 'O Policial deve permanecer em estado de alerta diante da necessidade de realizar outros disparos.', 'O Policial deve manter a visualização no agressor e no ambiente, mas sem tentar desarmar o infrator.', 'Caso o Policial tenha errado os disparos, deberá pedir reforço de outra guarnição.', 'Caso o agressor esteja sob efeito de substâncias tóxicas, o Policial deberá disparar novamente para impedir sua resistência.', 'B', 'CP', 2.0),

('69', 'A Lei nº 11.340/2016 e alterações, conhecida como Lei Maria da Penha, ao dispor sobre medida protetiva de urgência, prescreve: «Art. 12-C. Verificada a existência de risco atual ou iminente à vida ou à integridade física da mulher em situação de violência doméstica e familiar, ou de seus dependentes, o agressor será imediatamente afastado do lar, domicílio ou local de convivência com a ofendida:» Quando o Município não for sede de comarca e não houver delegado disponível no momento da denúncia, a medida protetiva de urgência será ordenada', 'pelo policial.', 'pelo Prefeito Municipal.', 'pela Guarda Municipal.', 'por assistente social.', 'pelo Prefeito ou Secretário Municipal designado.', 'A', 'CP', 2.0),

('70', 'Na hipótese relatada na questão anterior, o juiz será comunicado no prazo máximo de', '72 (setenta e duas) horas e decidirá, em igual prazo, sobre a manutenção ou a revogação da medida aplicada, devendo dar ciência ao Ministério Público concomitantemente.', '48 (quarenta e oito) horas e decidirá, em igual prazo, sobre a manutenção ou a revogação da medida aplicada, devendo dar ciência ao Ministério Público concomitantemente.', '5 (cinco) dias e decidirá, em igual prazo, sobre a manutenção ou a revogação da medida aplicada, devendo dar ciência ao Ministério Público concomitantemente.', '24 (vinte e quatro) horas e decidirá, em igual prazo, sobre a manutenção ou a revogação da medida aplicada, devendo dar ciência ao Ministério Público concomitantemente.', '10 (dez) dias e decidirá, em igual prazo, sobre a manutenção ou a revogação da medida aplicada, devendo dar ciência ao Ministério Público concomitantemente.', 'D', 'CP', 2.0),

('71', 'De acordo com as disposições gerais acerca dos Juizados Especiais Criminais (Lei nº 9.099/1995), assinale a assertiva correta.', 'Os juízes leigos não atuarão nos Juizados Especiais Criminais, apenas nos Cíveis.', 'Os crimes a que a lei comine pena máxima não superior a 2 (dois) anos, cumulada ou não com multa, são considerados de menor potencial ofensivo.', 'O Juizado Especial Criminal tem competência para julgar infrações penais de menor potencial ofensivo, excluídas as contravenções penais.', 'O processo perante o Juizado Especial objetiva, sempre que possível, a aplicação de pena privativa de liberdade.', 'O processo perante o Juizado Especial orientar-se-á pelos critérios da oralidade, complexidade, formalidade, economia processual e celeridade.', 'B', 'CP', 2.0),

('72', 'O artigo 76 da Lei nº 9.099/1995, ao dispor sobre a fase preliminar ao oferecimento da denúncia no Juizado Especial Criminal, preceitua: «Art. 76. Havendo representação ou tratando-se de crime de ação penal pública incondicionada, não sendo caso de arquivamento, o Ministério Público poderá propor a aplicação imediata de pena restritiva de direitos ou multas, a ser especificada na proposta». Trata-se de hipótese legal que autoriza a prevenção ou extinção do conflito, mediante o cumprimento de uma pena consensualmente ajustada ou pagamento de multa, por meio de', 'perdão judicial.', 'contenda criminal.', 'transação penal.', 'remissão penal.', 'remição da pena.', 'C', 'CP', 2.0),

('73', 'Tendo em vista as normas do Código de Trânsito Brasileiro (Lei nº 9.503/1997 e alterações) aplicáveis às Polícias Militares dos Estados, marque V para as afirmativas verdadeiras e F para as falsas. ( ) Compete ao órgão ou entidade executivo de trânsito estadual estabelecer, em conjunto com a Polícia Militar, as diretrizes para o policiamento ostensivo de trânsito, no âmbito de sua circunscrição. ( ) Compete à Policia Militar executar a fiscalização de trânsito, independentemente de celebração de convênio, como agente do órgão ou entidade executivo de trânsito ou executivo rodoviário estadual. ( ) O policial militar designado pela autoridade de trânsito com jurisdição sobre a via é agente competente para lavrar o auto de infração. ( ) Os dados estatísticos de trânsito consolidados pelo órgão ou entidade executivo de trânsito estadual devem compreender os registros de acidentes de trânsito coletados pela Polícia Militar. Assinale a sequência correta.', 'V, F, V, V', 'V, V, F, V', 'F, V, V, F', 'V, F, F, V', 'F, F, V, F', 'A', 'CP', 2.0),

('74', 'Nos termos da Lei nº 9.605/1998 e alterações, conhecida como Lei de Crimes Ambientais, os instrumentos utilizados na prática da infração ambiental, que forem apreendidos pela fiscalização, serão', 'imediatamente destruídos.', 'descaracterizados e destruídos.', 'avaliados e doados para instituições públicas.', 'descaracterizados e doados para instituições com fins beneficentes.', 'vendidos, garantida a sua descaracterização por meio de reciclagem.', 'E', 'CP', 2.0),

('75', 'Segundo a Lei nº 9.605/1998 e alterações, conhecida como Lei de Crimes Ambientais, quanto às penas restritivas de direito aplicáveis ao infrator pessoa física, é correto afirmar:', 'A suspensão de atividades será aplicada quando estas não estiverem obedecendo às prescrições legais.', 'A prestação de serviços à comunidade é pena prevista para danos à coisa pública ou tombada, mas não se aplica em caso de dano de coisa particular.', 'A prestação pecuniária, consistente no pagamento em dinheiro de importância fixada pelo juiz, não se destina à vítima, mas à entidade pública ou privada com fim social.', 'É prevista pena de interdição temporária de direito consistente em proibição de participar de licitações, pelo prazo máximo de dois anos.', 'O condenado à pena de recolhimento domiciliar deverá, sob vigilância, trabalhar, frequentar curso ou exercer atividade autorizada.', 'A', 'CP', 2.0),

('76', 'A Lei nº 11.346/2006, na sua redação atualizada, prevê que veículos, embarcações, aeronaves e quaisquer outros bens apreendidos nas ações de repressão aos crimes relacionados com o tráfico ilícito de drogas, mediante autorização judicial, sem prejuízo de outras providências, poderão ser usados por órgãos', 'do Poder Judiciário.', 'de polícia judiciária, militar e rodoviária.', 'do Ministério Público.', 'do Sistema Único de Saúde.', 'do Poder Legislativo.', 'B', 'CP', 2.0),

('77', 'Da ementa de julgamento de recurso em processo criminal envolvendo a condenação em primeiro grau da parte ré por tráfico internacional de drogas, perante o Tribunal Regional Federal da 3ª Região, extrai-se a seguinte narrativa: «(...) a informação da ré foi fundamental para a localização de Fulano de Tal, para a decretação de sua prisão, instauração de inquérito policial para investigar a participação de demais integrantes da organização criminosa, bem como posterior propositura do processo nº xxx contra o integrante da organização criminosa Fulano de Tal;» Com fundamento na Lei nº 11.346/2006, conhecida como Lei de Drogas, é possível deduzir, a partir dos fatos narrados, que a parte ré', 'colaborou com a investigação policial e foi beneficiada com cela especial na unidade prisional.', 'colaborou com a investigação criminal para obter proteção policial.', 'foi absolvida pelo benefício da delação premiada.', 'foi beneficiada pela delação premiada e obteve redução da pena.', 'colaborou com a investigação criminal, apesar de inexistir previsão de delação premiada na lei.', 'D', 'CP', 2.0),

('78', 'Constitui efeito da condenação por crime tipificado na Lei nº 7.716/1989, que define os crimes resultantes de preconceito de raça ou de cor, no caso de servidor público:', 'A suspensão dos direitos políticos por até três anos.', 'A perda do cargo ou função pública.', 'A declaração de inidoneidade.', 'O impedimento para contratar com o Poder Público.', 'A suspensão do cargo ou função pública, sem remuneração, por até dois anos.', 'B', 'CP', 2.0),

('79', 'Nos termos da Lei nº 10.826/2003, conhecida como Estatuto do Desarmamento, aquele que deixar de observar as cautelas necessárias para impedir que menor de 18 (dezoito) anos ou pessoa com deficiência mental se apodere de arma de fogo, que esteja sob sua posse ou que seja de sua propriedade, incorre no seguinte crime:', 'Omissão de cautela.', 'Posse irregular de arma de fogo.', 'Porte ilegal de arma de fogo.', 'Negligência qualificada.', 'Omissão negligente.', 'A', 'CP', 2.0),

('80', 'A perturbação do trabalho ou sossego alheios, por meio de gritaria, algazarra, ou abusando de instrumentos musicais ou sinais acústicos, nos termos da legislação brasileira, é conduta', 'enquadrada como crime relativo à polícia de costumes.', 'considerada como fato atípico na esfera penal.', 'enquadrada como contravenção penal sujeita à prisão simples ou multa.', 'considerada como crime contra a organização do trabalho.', 'enquadrada como contravenção penal sujeita, exclusivamente, à multa.', 'C', 'CP', 2.0);